UPDATE t_settlement_order
SET settlement_status = #{settlementStatus},
    payout_status = #{payoutStatus},
    audit_status = #{auditStatus}
WHERE settlement_no = #{settlementNo}

UPDATE t_payout_record
SET payout_status = #{payoutStatus},
    retry_count = #{retryCount}
WHERE payout_no = #{payoutNo}
